import React, { useEffect } from 'react';

import '../styles/CustomParallax.css'; // Asegúrate de tener el archivo CSS correspondiente
import { Container } from 'react-bootstrap';

const CustomParallax = ({ layers, scrollPercentage }) => {
  const containerRef = useRef(null);

  useEffect(() => {
    if (!containerRef.current) return;

    const handleScroll = () => {
      const containerWidth = containerRef.current.offsetWidth;
      layers.forEach((layer, index) => {
        const mount = document.querySelector(`#layer${index}`);
        if (mount) {
          const speed = layer.speed;
          const initialOffset = parseFloat(layer.initialOffset?.replace('px', '') || 0);
          const travelDistance = containerWidth + mount.offsetWidth; // Distancia de viaje para el bucle
          const position = (scrollPercentage / 100) * travelDistance * speed - initialOffset;
          mount.style.transform = `translateX(${position}px)`;
        }
      });
    };

    handleScroll();

    window.addEventListener('scroll', handleScroll);
    return () => window.removeEventListener('scroll', handleScroll);
  }, [layers, scrollPercentage]);

  return (
    <div className="section_parallax" ref={containerRef}>
      <Container>
        {layers.map((layer, index) => (
          <img
            key={index}
            id={`layer${index}`}
            src={layer.image}
            alt={`Layer ${index}`}
            className="parallax-layer"
            style={{ zIndex: layers.length - index }}
          />
        ))}
      </Container>
    </div>
  );
};

export default CustomParallax;
